create index if not exists idx_contratos_status_codigo on public.contratos(status_codigo); create index if not exists idx_unidades_instaladas_status_codigo on public.unidades_instaladas(status_codigo); create index if not exists idx_ordens_manutencao_criado_por on public.ordens_manutencao(criado_por); create index if not exists idx_ordens_manutencao_status_codigo on public.ordens_manutencao(status_codigo); create index if not exists idx_pendencias_ordem_manutencao_status_codigo on public.pendencias_ordem_manutencao(status_codigo); create index if not exists idx_atendimentos_ordens_criado_por on public.atendimentos_ordens(criado_por); create index if not exists idx_atendimentos_ordens_status_codigo on public.atendimentos_ordens(status_codigo); create index if not exists idx_equipes_id_terceira on public.equipes(id_terceira); create index if not exists idx_equipes_criado_por on public.equipes(criado_por); create index if not exists idx_atendimentos_executados_status_codigo on public.atendimentos_executados(status_codigo); create index if not exists idx_movimentacoes_criado_por on public.movimentacoes(criado_por); create index if not exists idx_movimentacoes_tipo_codigo on public.movimentacoes(tipo_codigo); create index if not exists idx_historico_unidade_id_unidade on public.historico_unidade(id_unidade); create index if not exists idx_notificacoes_id_ordem on public.notificacoes(id_ordem);
grant select, insert on table public.historico_unidade, public.notificacoes to authenticated;
drop policy if exists "historico_unidade_select_gestor" on public.historico_unidade; create policy "historico_unidade_select_gestor" on public.historico_unidade for select to authenticated using (private.is_gestor((select auth.uid()))); comment on policy "historico_unidade_select_gestor" on public.historico_unidade is 'Historico tecnico consolidado fica restrito a gestor no MVP.';
drop policy if exists "historico_unidade_insert_gestor" on public.historico_unidade; create policy "historico_unidade_insert_gestor" on public.historico_unidade for insert to authenticated with check (private.is_gestor((select auth.uid()))); comment on policy "historico_unidade_insert_gestor" on public.historico_unidade is 'Somente gestor registra historico manual de unidade.';
drop policy if exists "notificacoes_select_gestor" on public.notificacoes; create policy "notificacoes_select_gestor" on public.notificacoes for select to authenticated using (private.is_gestor((select auth.uid()))); comment on policy "notificacoes_select_gestor" on public.notificacoes is 'Notificacoes ficam restritas a gestor no MVP.';
drop policy if exists "notificacoes_insert_gestor" on public.notificacoes; create policy "notificacoes_insert_gestor" on public.notificacoes for insert to authenticated with check (private.is_gestor((select auth.uid()))); comment on policy "notificacoes_insert_gestor" on public.notificacoes is 'Somente gestor cria notificacoes no MVP.';;
